// src/pages/Friends.jsx — with Chat button
import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { friendsAPI } from '../services/api';
import toast from 'react-hot-toast';
import './Friends.css';

export default function Friends() {
  const [tab,      setTab]      = useState('friends');
  const [friends,  setFriends]  = useState([]);
  const [requests, setRequests] = useState({ incoming: [], outgoing: [] });
  const [loading,  setLoading]  = useState(true);
  const [username, setUsername] = useState('');
  const [sending,  setSending]  = useState(false);
  const navigate = useNavigate();

  const load = async () => {
    setLoading(true);
    try {
      const [fr, rq] = await Promise.all([friendsAPI.getAll(), friendsAPI.getRequests()]);
      setFriends(fr.data.data.friends);
      setRequests(rq.data.data);
    } catch { toast.error('Could not load'); }
    finally { setLoading(false); }
  };

  useEffect(() => { load(); }, []);

  const sendRequest = async (e) => {
    e.preventDefault();
    if (!username.trim()) return;
    setSending(true);
    try {
      await friendsAPI.sendRequest(username.trim());
      toast.success('Friend request sent! 🎉');
      setUsername('');
      load();
    } catch (err) { toast.error(err.response?.data?.message || 'Could not send'); }
    finally { setSending(false); }
  };

  const respond = async (id, action) => {
    try {
      await friendsAPI.respond(id, action);
      toast.success(action === 'accept' ? 'Friend added! 🎉' : 'Request declined');
      load();
    } catch (err) { toast.error(err.response?.data?.message || 'Error'); }
  };

  const removeFriend = async (id, name) => {
    if (!window.confirm(`Remove ${name} from friends?`)) return;
    try {
      await friendsAPI.remove(id);
      toast.success('Friend removed');
      load();
    } catch { toast.error('Could not remove'); }
  };

  const startChat = (friendId) => {
    navigate(`/chat/${friendId}`);
  };

  return (
    <div className="friends-page page-enter">
      <div className="container-sm" style={{ paddingTop: 88 }}>
        <div className="friends-header">
          <div>
            <div className="section-eyebrow">Your Circle</div>
            <h1 className="section-title">Friends 👥</h1>
          </div>
        </div>

        {/* Add friend */}
        <div className="card add-friend-card">
          <div className="add-friend-title">➕ Add a Friend</div>
          <p className="add-friend-sub">Enter your friend's exact username to send a request</p>
          <form className="add-friend-form" onSubmit={sendRequest}>
            <input
              className="input"
              placeholder="e.g. FoxyAlex"
              value={username}
              onChange={e => setUsername(e.target.value)}
            />
            <button className="btn btn-primary" type="submit" disabled={sending || !username.trim()}>
              {sending ? <span className="spinner" /> : 'Send Request'}
            </button>
          </form>
        </div>

        {/* Tabs */}
        <div className="friends-tabs">
          {[
            { id: 'friends',  label: `👥 Friends (${friends.length})` },
            { id: 'incoming', label: `📩 Incoming (${requests.incoming?.length || 0})` },
            { id: 'outgoing', label: `📤 Sent (${requests.outgoing?.length || 0})` },
          ].map(t => (
            <button key={t.id} className={`friends-tab ${tab === t.id ? 'active' : ''}`} onClick={() => setTab(t.id)}>
              {t.label}
            </button>
          ))}
        </div>

        {loading ? (
          <div style={{textAlign:'center',padding:'48px',color:'var(--text3)'}}>
            <span className="spinner spinner-lg" />
          </div>
        ) : (
          <>
            {/* Friends list */}
            {tab === 'friends' && (
              friends.length === 0 ? (
                <div className="empty-state">
                  <div className="icon">👥</div>
                  <h3>No friends yet!</h3>
                  <p>Send a friend request to a classmate or someone you know.</p>
                </div>
              ) : (
                <div className="friends-list">
                  {friends.map(f => (
                    <div key={f.id} className="friend-row card">
                      <div className="avatar avatar-md" style={{ background: f.avatar_color || '#FFE5E5' }}>
                        {f.avatar_emoji || '🦊'}
                      </div>
                      <div className="friend-info">
                        <div className="friend-name">{f.display_name}</div>
                        <div className="friend-meta">
                          @{f.username} · friends since {new Date(f.friends_since).toLocaleDateString()}
                        </div>
                      </div>
                      <div className="friend-actions">
                        {/* 💬 Chat button */}
                        <button
                          className="btn btn-primary btn-sm"
                          onClick={() => startChat(f.id)}
                          title={`Chat with ${f.display_name}`}
                        >
                          💬 Chat
                        </button>
                        <span className="badge badge-green">✓ Friend</span>
                        <button
                          className="btn btn-ghost btn-sm"
                          onClick={() => removeFriend(f.id, f.display_name)}
                        >
                          Remove
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              )
            )}

            {/* Incoming */}
            {tab === 'incoming' && (
              requests.incoming?.length === 0 ? (
                <div className="empty-state">
                  <div className="icon">📩</div>
                  <h3>No pending requests</h3>
                </div>
              ) : (
                <div className="friends-list">
                  {requests.incoming.map(r => (
                    <div key={r.id} className="friend-row card">
                      <div className="avatar avatar-md" style={{ background: '#FFE5E5' }}>
                        {r.avatar_emoji || '🦊'}
                      </div>
                      <div className="friend-info">
                        <div className="friend-name">{r.display_name}</div>
                        <div className="friend-meta">@{r.username} wants to be friends</div>
                        {r.parent_status === 'pending' && (
                          <span className="badge badge-amber" style={{marginTop:4}}>
                            ⏳ Waiting for parent approval
                          </span>
                        )}
                      </div>
                      <div className="friend-actions">
                        <button className="btn btn-primary btn-sm" onClick={() => respond(r.id, 'accept')}>Accept</button>
                        <button className="btn btn-ghost btn-sm"   onClick={() => respond(r.id, 'decline')}>Decline</button>
                      </div>
                    </div>
                  ))}
                </div>
              )
            )}

            {/* Outgoing */}
            {tab === 'outgoing' && (
              requests.outgoing?.length === 0 ? (
                <div className="empty-state">
                  <div className="icon">📤</div>
                  <h3>No sent requests</h3>
                </div>
              ) : (
                <div className="friends-list">
                  {requests.outgoing.map(r => (
                    <div key={r.id} className="friend-row card">
                      <div className="avatar avatar-md" style={{ background: '#E5F5FF' }}>
                        {r.avatar_emoji || '🦊'}
                      </div>
                      <div className="friend-info">
                        <div className="friend-name">{r.display_name}</div>
                        <div className="friend-meta">@{r.username}</div>
                      </div>
                      <div className="friend-actions">
                        {r.parent_status === 'pending'
                          ? <span className="badge badge-amber">⏳ Parent reviewing</span>
                          : r.status === 'accepted'
                          ? <span className="badge badge-green">✓ Accepted</span>
                          : <span className="badge badge-coral">⏳ Pending</span>
                        }
                      </div>
                    </div>
                  ))}
                </div>
              )
            )}
          </>
        )}
      </div>
    </div>
  );
}
